+    config,
+    agentSessionKey: "agent:main:main",
+    modelProvider: "openai",
+    modelId: "gpt-5.4",
+    ...overrides,
+  };
+  if ("agentId" in overrides && !("agentSessionKey" in overrides)) {
+    delete params.agentSessionKey;
+  }
+  return params;
+}
